1	export function nextGeneration(cells: [number, number][]): [number, number][] {
2	  const isAlive = (x: number, y: number): boolean =>
3	    cells.some(([cx, cy]) => cx === x && cy === y);
4	
5	  const neighborOffsets: [number, number][] = [
6	    [-1, -1], [-1, 0], [-1, 1],
7	    [0, -1], [0, 1],
8	    [1, -1], [1, 0], [1, 1],
9	  ];
10	
11	  const countNeighbors = (x: number, y: number): number =>
12	    neighborOffsets.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
13	
14	  const survivors = cells.filter(([x, y]) => {
15	    const neighbors = countNeighbors(x, y);
16	    return neighbors === 2 || neighbors === 3;
17	  });
18	
19	  const births: [number, number][] = [];
20	  for (const [x, y] of cells) {
21	    for (const [dx, dy] of neighborOffsets) {
22	      const nx = x + dx;
23	      const ny = y + dy;
24	      if (!isAlive(nx, ny) && countNeighbors(nx, ny) === 3) {
25	        if (!births.some(([bx, by]) => bx === nx && by === ny)) {
26	          births.push([nx, ny]);
27	        }
28	      }
29	    }
30	  }
31	
32	  return [...survivors, ...births];
33	}
34

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two live cells that each have only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep alive a live cell with three neighbors (survival)", () => {
15	    // (1,0) has three live neighbors: (0,0), (2,0), (1,1) -> survives
16	    expect(nextGeneration([[0, 0], [2, 0], [1, 1], [1, 0]])).toContainEqual([1, 0]);
17	  });
18	  it("should kill a live cell with four neighbors (overpopulation)", () => {
19	    // Center cell (1,1) has four live neighbors -> dies by overpopulation
20	    expect(
21	      nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]])
22	    ).not.toContainEqual([1, 1]);
23	  });
24	  it("should bring a dead cell with exactly three neighbors to life (reproduction)", () => {
25	    // Dead cell (1,1) has three live neighbors: (0,0), (1,0), (0,1) -> comes alive
26	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
27	  });
28	  it.todo("should oscillate a blinker, including negative coordinates");
29	  it.todo("should leave a block still life unchanged");
30	});
