const survivors = cells.filter(([x, y]) => {
  const neighbors = countNeighbors(x, y);
  return neighbors === 2 || neighbors === 3;
});

const deadNeighbors = new Map<string, [number, number]>();
for (const [x, y] of cells) {
  for (const [dx, dy] of neighborOffsets) {
    const candidate: [number, number] = [x + dx, y + dy];
    if (!isAlive(candidate[0], candidate[1])) {
      deadNeighbors.set(candidate.join(","), candidate);
    }
  }
}

const births = [...deadNeighbors.values()].filter(
  ([x, y]) => countNeighbors(x, y) === 3
);

return [...survivors, ...births];

